var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"래시포드 씨. 저희는 무사히 설치 끝냈어요.","JPN":"ラッシュフォードさん。こちらは無事設置を完了しましたよ。","ENG":"Miss Rashford. We're all set up here.","TWN":"雷斯福特，我們已經順利設置完畢。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이쪽도 문제없습니다. 그럼 바로 작동시켜 보죠.","JPN":"こちらも問題ありません。それでは作動させてみましょう。","ENG":"No problems here. Let's get them online.","TWN":"這邊也沒問題，那就立刻啓動吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"뭐지……?","JPN":"何だ……？","ENG":"What...?","TWN":"怎麼會……？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이상해. 침식파가 약해지는 구간이 전혀 보이지 않아.","JPN":"おかしい。侵食波が弱まる区間がまったく見当たらない。","ENG":"Something's not right. There isn't a place where the Corruption ray weakens.","TWN":"奇怪，完全看不到侵蝕波變弱的區段。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"심지어 한 곳은… 침식파가 비정상적으로 집중되어 있어.","JPN":"しかも一か所は……侵食波が異常に集中している。","ENG":"But there's one place... where the Corruption ray is abnormally strong.","TWN":"甚至有一個地方…侵蝕波異常集中。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"저… 래시포드 씨?","JPN":"あの……ラッシュフォードさん？","ENG":"Um... Miss Rashford?","TWN":"那個… 雷斯福特？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L14_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"어쩌면 고준위 침식파가 흐르는 좌표에 성유물이 있는 게 아닐까요?","JPN":"もしかしたら、高レベルの侵食波が流れてる座標に聖遺物があるんじゃないでしょうか？","ENG":"What if the coordinates where the Corruption ray is focusing is where the Holy Relic is?","TWN":"聖遺物會不會就在高段侵蝕波流動的座標？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…네? 그게 무슨 말씀이시죠?","JPN":"……はい？　それはどういうことですか？","ENG":"Huh? What do you meant by that?","TWN":"……嗯？那是什麼意思？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"성유물은 침식을 막아 주던 도구라고 들었어요.","JPN":"聖遺物は侵食を防いでいた道具だと聞きました。","ENG":"I heard that the Holy Relic was a tool used to block out Corruption.","TWN":"我聽說聖遺物是抵擋侵蝕的工具。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"이건 가정일 뿐이지만… 그 원리가 침식파를 흡수하기 때문이라면, 오히려 침식파가 강한 곳이 정답일 수도 있겠다는 생각이 들어서요.","JPN":"これは推測ですけど……その原理が侵食波を吸収するためだったら、むしろ侵食波が強い場所が正解かもしれないと思ったんです。","ENG":"It's just a hypothesis, but... What if it prevented the Corruption ray by absorbing it? That would explain why it's abnormally strong in that place.","TWN":"雖然這只是假設…如果其原理是吸收侵蝕波，那侵蝕波強的地方或許反而有正確答案。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그렇게 생각하면 침식파가 높은 이유도 납득이 가는군요.","JPN":"そう考えれば侵食波のレベルが高い理由も納得できますね。","ENG":"That could explain why...","TWN":"這樣的話，似乎也能理解侵蝕波高的理原因。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지금으로선 달리 특정할 만한 장소가 없으니, 한나 씨의 의견을 따라서…","JPN":"現時点では別に特定できる場所がないし、ハンナさんの意見に従って……","ENG":"Then, since there is no other location we can pinpoint, let's follow Hanna's suggestion and–","TWN":"現在沒什麼特別鎖定的地方，就照漢娜的意思…"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"장교님! 조심하십시오!","JPN":"将校！　お気をつけください！","ENG":"Officer Rashford! Watch out!","TWN":"軍官！請小心！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…음?","JPN":"……む？","ENG":"Hmm?","TWN":"…嗯？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"큭…?!","JPN":"くっ……！？","ENG":"Kgh...?!","TWN":"唔…？！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GUARD_BORDER_NULL_NULL","text":{"KOREA":"침식체의 기습이다! 장교님을 엄호해!","JPN":"侵食体の奇襲だ！　将校を援護しろ！","ENG":"We're being ambushed! Protect Officer Rashford!","TWN":"有侵蝕體偷襲！ 掩護軍官！"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_BORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"괜찮으십니까?","JPN":"大丈夫ですか？","ENG":"Are you okay?","TWN":"你沒事吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그래. 네가 막아 준 덕분에 살았어.","JPN":"ああ。あなたが防御してくれたおかげで助かった。","ENG":"Yes. Thank you.","TWN":"沒事，幸虧你替我擋著我才沒死。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"넌 다치지 않았나?","JPN":"あなたは怪我はないか？","ENG":"Did you get hurt?","TWN":"你沒受傷吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"아, 전 괜찮습니다. 그런데…","JPN":"あ、僕は大丈夫です。でも……","ENG":"Oh, I'm okay. But...","TWN":"喔，我沒事，可是…"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"관측장비까지 지키는 건 무리였습니다. 다시 사용하기는 어려울 것 같아요.","JPN":"観測装備までは守れませんでした。もう一度使用するのは難しそうです。","ENG":"I couldn't save the observation device. It may be broken.","TWN":"沒能保住監測設備，好像沒辦法再使用了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"상관없다. 좌표는 이미 확보했어.","JPN":"構わない。すでに座標は確保した。","ENG":"It doesn't matter. We already have the coordinates.","TWN":"無所謂，座標已經確定了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"서둘러 이동하지.","JPN":"急いで行こう。","ENG":"Let's get moving.","TWN":"趕緊移動吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HANNA_NPC_NULL_ARMED","text":{"KOREA":"흐아앙, 래시포드 씨! 갑자기 통신이 끊겨서 무슨 일이라도 생긴 줄 알았다고요!","JPN":"うわーん、ラッシュフォードさん！　いきなり通信が切れちゃって何かあったかと思いましたよ！","ENG":"Huaah...! Miss Rashford! I thought something happened to you because your comms cut off!","TWN":"嗚嗚嗚，雷斯福特！說到一半突然斷掉，我還以爲你發生什麼事呢！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANNA_NPC_NULL_ARMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L47_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"괜한 걱정을 끼쳤군요. 저는 무사합니다.","JPN":"心配をおかけしました。私は無事です。","ENG":"Sorry about that. I'm fine.","TWN":"讓你擔心了，我沒事。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"저 우람한 슈트와 가냘픈 목소리의 조화는 좀처럼 적응이 안 되는군.","JPN":"あのデカいスーツとか弱い声の組み合わせにはどうも慣れないな。","ENG":"I still can't get used to hearing that frail voice from that burly suit...","TWN":"那麼壯的戰鬥服和嬌弱的聲音，真的很難搭在一起。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"뭔가 찾는 눈치인데. 침식체의 존재라도 느낀 건가?","JPN":"何か探してるようだが。侵食体の存在でも感じたのか？","ENG":"Are you looking for something? Do you sense another C.O. around here?","TWN":"你好像在找什麼，是有感受到侵蝕體的存在嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"침식체의 존재는 외성을 떠날 때부터 사방에서 느껴졌어.","JPN":"侵食体の存在は外郭を発った頃からあちこちで感じていたの。","ENG":"C.O.s have been lurking around us ever since we left the outer castle.","TWN":"離開外城後，到處都可以感受到侵蝕體存在。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"진입하기 전에 잠시 둘러보고 있었을 뿐이야. 내 고향이니까.","JPN":"進入する前にちょっと見回っていただけ。私の故郷だから。","ENG":"I'm just taking a look around before we go in. This was my home after all.","TWN":"只是進去前稍微繞一下而已，因爲是我的家鄉。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"음? 고향이라고?","JPN":"うむ？　故郷だと？","ENG":"Huh? Your home?","TWN":"嗯？你的家鄉？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"정확히는 내가 태어나기 전에 엄마가 살던 고향이야.","JPN":"正確には私が生まれる前にお母さんが住んでいた故郷よ。","ENG":"Well, it's where my mother used to live before I was born.","TWN":"正確來說，是媽媽在我出生前住過的地方。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"원래 여긴 작은 마을이었어. 침식의 날이 오지 않았으면 나도 여기서 살았을지도 모르지.","JPN":"ここは元々小さな村だった。侵食の日が来なかったら、私もここに住んでいたかもしれないね。","ENG":"It was originally a small town. If it wasn't for the Day of Corruption, perhaps I'd be still living here.","TWN":"這裡本來是一個小鎮，要是侵蝕之日沒有來臨，我可能就會生活在這裡。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"우연치고는 얄궂군. 20년도 더 지나서 이런 식으로 고향에 돌아오다니.","JPN":"偶然にしては皮肉だな。20年も過ぎてこんな形で故郷に戻ることになるとは。","ENG":"Fate can be cruel sometimes. Coming home like this after 20 years...","TWN":"還真巧，20幾年過去後，竟然以這樣方式回到家鄉。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"……맞아. 얄궂은 일이지.","JPN":"……そう。皮肉なことにね。","ENG":"Yes... It is cruel.","TWN":"……沒錯，真的很巧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"엄마는 돈도 안 되는 의료 봉사에 매달려 살았어.","JPN":"お母さんはお金にもならない医療ボランティアで忙しかった。","ENG":"Mother was completely devoted to volunteering in medical services, which didn't make any money.","TWN":"媽媽靠著沒什麼錢的醫療志工生活。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"내가 먹고 살기도 빠듯한데 왜 그런 일을 하냐고 투정 부리면, 언제나 자랑하듯 말씀하셨지.","JPN":"私が生活もロクにできないのにどうしてそんな仕事をしてるのかと愚痴を言うと、いつも自慢するようにこう言ってたの。","ENG":"Whenever I complained about why she would do that when we were struggling to make ends meet, she would always reply with pride in her voice.","TWN":"我還跟媽媽發牢騷說，連飯都吃不飽，為什麼要做那種事。而媽媽總是很驕傲地說，"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"침식체에게 모든 걸 잃은 줄 알았던 그 날, 왕립군이 나타나 우리 목숨을 구해 줬다고.","JPN":"侵食体によってすべてを失うと思ったあの日、王立軍が現れて私たちを救ってくれたって。","ENG":"She told me that when she thought she was going to lose everything to the C.O., the Royal Army stepped in and saved us.","TWN":"我以為會因為侵蝕體而失去一切的那一天，是皇家軍隊出現救我們一命的。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그러니 우리도 그들처럼 힘든 사람들을 돕는 게 당연하다고.","JPN":"だから自分たちも彼らのように苦しんでる人を助けてあげて当然だって。","ENG":"And that's why it's only natural that we help those in need too.","TWN":"所以我們也應該幫助像他們這樣有困難的人。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"대장의 어머니도 훌륭한 의사분이셨나 보군. 지금은 수도에 계신 건가?","JPN":"隊長の母上も立派な医者だったようだな。今は首都にお住まいか？","ENG":"I see that your mother was also an excellent doctor, Captain. Is she in the capital now?","TWN":"看來隊長的媽媽也是一位好醫生呢，她現在在首都嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"돌아가셨어. 침식증후군으로.","JPN":"亡くなった。侵食症候群で。","ENG":"She passed away. From the Corruption Syndrome.","TWN":"她去世了，因為侵蝕症候群的關係。"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그렇게 혼자가 되서야 깨달았지.","JPN":"そうやって一人になってやっと気づいたの。","ENG":"It's only when I was alone that I realized...","TWN":"就這樣留下我一個人，於是我才發現。"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"침식 증후군을 치료한다는 건 허상이고, 환자의 고통만 연장할 뿐이라는 걸.","JPN":"侵食症候群を治療するというのは夢物語で、患者の苦痛を長引かせるだけなんだってことを。","ENG":"Treating the Corruption Syndrome is nothing but an illusion. It was only prolonging their suffering.","TWN":"原來治療侵蝕症候群是一種假象，只會延長病人的痛苦。"},"stage":{"bg":"WARZONE_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 난 어머니처럼 감염되는 대신, 워치를 얻었어. 그래서 국경수비대로 온 거야.","JPN":"でも私はお母さんのように感染する代わりにウォッチを手に入れたの。だから国境守備隊に来たわけ。","ENG":"But instead of getting infected like my mother, I received a Watch and became a Counter. That's why I decided to join the Border Guards.","TWN":"不過我沒有像媽媽一樣受到感染，而是得到能量環，所以才會加入國境護衛隊。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그 결정을… 후회하진 않나?","JPN":"その決定を……後悔してはいないか？","ENG":"Do you... ever regret making that decision?","TWN":"你不後悔…覺醒嗎？"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"침식으로부터 환자를 구하진 못해도, 침식체로부터 사람들을 구할 수는 있으니까.","JPN":"侵食から患者を救うことはできないけど、侵食体から人を守ることはできるから。","ENG":"Even if I can't save people from the Corruption, I can save them from C.O.s.","TWN":"就算不能從侵蝕中救出病患，至少能從侵蝕體手中把人救出來。"},"stage":{"bg":"WARZONE_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"잘한 결정이라고 생각해.","JPN":"いい決定だったと思う。","ENG":"I believe I made the right choice.","TWN":"我覺得這是正確的決定。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그렇다면 다행이군.","JPN":"それならよかったな。","ENG":"If that's the case, I'm glad to hear that.","TWN":"那就好。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"지휘관님. 지시하신 대로 쐐기 대포의 설치를 마쳤습니다.","JPN":"指揮官。指示どおり、くさび大砲の設置を完了しました。","ENG":"Sir. The Ironshot Cannons are in place as you ordered.","TWN":"指揮官，已經按照你的指示設好楔子大砲。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"입구의 잔해도 모두 치웠습니다. 지금 당장이라도 진입할 수 있어요.","JPN":"入口の残骸も全て片付けました。今すぐにでも進入できます。","ENG":"We've cleared the debris from the entrance as well. We may enter at any time now.","TWN":"門口的殘骸也已經清理乾淨，現在就可以進去。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다들 수고 많았다.","JPN":"みんな、ご苦労だった。","ENG":"Well done.","TWN":"大家辛苦了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"우리가 진입할 곳은 고준위 침식파가 흐르는 장소다.","JPN":"我々が進入する場所は高レベルの侵食波が流れているところだ。","ENG":"The place we are about to enter contains high levels of Corruption ray.","TWN":"我們要進入的地方，是高段侵蝕波流動的地方。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"위험한 침식체가 도사리고 있을지도 모른다. 마지막까지 다들 방심하지 말도록.","JPN":"危険な侵食体が潜んでいるかもしれない。みんな、最後まで気を抜くな。","ENG":"Hostile C.O.s may be lurking. Don't let your guard down until the end.","TWN":"很可能到處都有危險的侵蝕體，不到最後大家千萬不能鬆懈。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그럼 엘라 대장. 명령을.","JPN":"それではエラ隊長。ご命令を。","ENG":"Captain Ella, what are your orders?","TWN":"那麼，艾拉隊長，請下令。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"……목표로 하는 성유물 회수까지 앞으로 한 걸음이면 된다.","JPN":"……目標の聖遺物を回収するまであと一歩だ。","ENG":"...We're this close to retrieving the Holy Relic.","TWN":"……距離回收目標聖遺物只差一步。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"남부 국경수비대! 전원 장교님을 호위하며 진입한다!","JPN":"南部国境守備隊！　総員、将校を護衛しながら進入する！","ENG":"Southern Border Guards! Escort the officer! Forwards!","TWN":"南方國境護衛隊！全體掩護軍官進入！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};